#include <iostream>
#include <climits>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;

    int max_val = INT_MIN;
    int max_i = 1, max_j = 1;

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            int x;
            cin >> x;
            if (x > max_val) {
                max_val = x;
                max_i = i;
                max_j = j;
            }
        }
    }

    cout << max_val << " " << max_i << " " << max_j << endl;
    return 0;
}
